// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Random;

import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.parser.sparql.SPARQLParser;

/**
 * Seed trees from the scope-safety fixture corpus (rdf4j-sail-testsuite classpath resources): 50 curated queries plus
 * 10 adversarial ones, each purpose-built around the scoping traps the checker's known bug classes live in. Each parsed
 * tree is paired with mutator-derived candidates. Unparseable or missing queries are skipped and counted.
 */
final class CorpusQuerySource {
	private final List<TupleExprMutator> mutators = MutatorLibrary.all();
	private int skipped;

	List<TreePair> pairs(long seed, int mutationsPerQuery) {
		List<TreePair> result = new ArrayList<>();
		for (String queryId : queryIds()) {
			Optional<TupleExpr> parsed = parse(queryId);
			if (parsed.isEmpty()) {
				skipped++;
				continue;
			}
			Random rnd = new Random(seed ^ queryId.hashCode());
			for (int i = 0; i < mutationsPerQuery; i++) {
				TupleExprMutator mutator = mutators.get(rnd.nextInt(mutators.size()));
				Optional<TupleExpr> candidate = mutator.apply(parsed.get(), rnd);
				if (candidate.isEmpty()) {
					continue;
				}
				result.add(new TreePair(
						queryId + "#" + mutator.name(), "scope-safety", seed,
						List.of(mutator.name()), parsed.get().clone(), candidate.get(),
						mutator.expectation()));
			}
		}
		return result;
	}

	int skippedQueries() {
		return skipped;
	}

	private List<String> queryIds() {
		List<String> ids = new ArrayList<>();
		for (int i = 1; i <= 50; i++) {
			ids.add(String.format("scope-safety/queries/q%02d.rq", i));
		}
		for (int i = 1; i <= 10; i++) {
			ids.add(String.format("scope-safety/adversarial/queries/a%02d.rq", i));
		}
		return ids;
	}

	private Optional<TupleExpr> parse(String resource) {
		try (InputStream input = CorpusQuerySource.class.getClassLoader().getResourceAsStream(resource)) {
			if (input == null) {
				return Optional.empty();
			}
			String query = new String(input.readAllBytes(), StandardCharsets.UTF_8);
			return Optional.of(new SPARQLParser().parseQuery(query, "urn:fuzz:base").getTupleExpr());
		} catch (IOException | RuntimeException e) {
			return Optional.empty();
		}
	}
}
